  @Test
  public void test_sequenceCreator() throws Exception {
    ISequence<String> seq = Sequence.fromClosure(() -> {
      return (Iterable<String>) () -> {
        return new YieldingIterator<String>() {
          private int __CP__ = 0;
          protected boolean moveToNext() {
__loop__:
            do {
__switch__:
              switch (this.__CP__) {
                case -1:
                  assert false : "Internal error";
                  return false;
                case 2:
                  this.__CP__ = 3;
                  this.yield("welcome");
                  return true;
                case 3:
                  this.__CP__ = 4;
                  this.yield("to");
                  return true;
                case 4:
                  this.__CP__ = 1;
                  this.yield("2023");
                  return true;
                case 0:
                  this.__CP__ = 2;
                  break;
                default:
                  break __loop__;
              }
            } while (true);
            return false;
          }
        };
      };
    });

    Assert.assertEquals("welcome", Sequence.fromIterable(seq).first());
  }
